        'ВЕС', 'Общая\nактивность', 'Трен', 'Общие\nзатраты', 'Целевой\nдефицит%', 'Нужно\nсъесть', 'съедено\nза день', 'Факт\nдефицит\n%', 'Дефицит\nккал', '',
        'Приёмов', 'Сон\nчасы', 'Сон\nкач', 'Сон\nкоммент', 'Стресс', 'Самоч', 'Настроение', 'День\nкоммент'
