        const simplePct = rows28.map(r => r.simplePct);
        const complexPct = rows28.map(r => r.complexPct);

        const U = (global.HEYS && HEYS.utils) || { lsGet: (k, d) => d };
        const profile = U.lsGet('heys_profile', {});
